var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"리타 언니......? 정말 언니예요?","JPN":"リタお姉ちゃん……？　本当にお姉ちゃんですか？","ENG":"Rita? Is that really you?","TWN":"麗塔姐姐……？真的是姐姐嗎？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"꼬맹이? 네가 여길 어떻게......?","JPN":"ガキ？　お前どうやってここに……？","ENG":"Kid? But how did you get here?","TWN":"小鬼？你怎麼到這裡來的……？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"계속 낯선 곳에서 헤매고 있었는데...... 처음 보는 여자 분이 이리로 안내해 줬어요.","JPN":"見知らぬ場所で迷子になっていたら……初めて見る女性の方がこちらに案内してくれました。","ENG":"I kept wandering around in an unfamiliar place... But then this lady I never met before led me here.","TWN":"我一直在陌生的地方徘徊……有個第一次見面的女士帶我到這裡。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......그래. 그랬구나.","JPN":"ああ、そうか……","ENG":"Right. I see.","TWN":"……啊，原來如此。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그 때...... 단골 술집으로 가자고 했던 약속, 기억나?","JPN":"あの時……行きつけのバーに行こうといった約束、覚えているか？","ENG":"Hey... Do you remember how we promised to go to my favorite bar?","TWN":"那時候……還記得一起到我經常光顧的酒館的約定嗎？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"네. 여기였죠. 기억해요.","JPN":"はい、ここでしたよね。覚えています。","ENG":"Yes. It was right here. I remember.","TWN":"嗯，就是這裡吧。我記得。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"취해 있는 언니를 사무소로 데리고 오느라 몇 번 들렀잖아요.","JPN":"酔っ払ったお姉ちゃんのお迎えで、何度も来たことありますよ。","ENG":"I came by a few times to take you back to the office when you got trashed.","TWN":"為了把喝醉的姐姐帶回事務所，我都不知道來過幾次了啊。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"여기서 너한테 전부 얘기하려고 했어.","JPN":"ここでお前に全部話すつもりだった。","ENG":"I was going to tell you everything here.","TWN":"我本來想在這裡將一些話全部告訴你。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이제까지 다정하게 대해 주지 못해서 미안하다고.","JPN":"今まで優しくしてあげられなくてごめんね、と。","ENG":"About how sorry I am for never being kind to you.","TWN":"我一直對你很嚴厲，很抱歉。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"더 좋은 걸 가르쳐 주지 못해서, 더 좋은 환경에서 지내게 해 주지 못해서......","JPN":"もっと色々教えてあげられなくて、もっといい環境の暮らしをさせてあげられなくて……","ENG":"For not teaching you better... For not providing a better environment for you...","TWN":"沒能把更好的教給你，沒能讓你在更好的環境中生活……"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그런 성가신 일에 휘말리게 만들어서 미안하다고.","JPN":"あんなことに巻き込んでしまって申し訳ない、と。","ENG":"And for getting you involved in that mess.","TWN":"讓你捲入麻煩之中，很抱歉。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"나는...... 너에게만은 떳떳한 어른이고 싶었어.","JPN":"私は……お前にだけは、堂々とした大人でいたかった。","ENG":"I... wanted to be a proud grown-up, at least in your eyes.","TWN":"我……只想在你面前成為堂堂正正的大人。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"하지만 결국엔 허세만 가득찬 바보였지.","JPN":"でも結局、格好つけるだけのバカだった。","ENG":"But it turned out I was just full of it.","TWN":"但最終卻成了個虛張聲勢的傻子。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"나는 네게 아무것도 못 해 줬어.","JPN":"私はお前に何もしてあげられなかった。","ENG":"I never got to do anything nice for you.","TWN":"我沒能為你做任何事情。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"아니에요, 언니.","JPN":"違います、お姉ちゃん。","ENG":"No, Rita.","TWN":"不，姐姐。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"사실은......","JPN":"実は……","ENG":"Actually...","TWN":"其實……"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"헤헤, 저도 쑥스러워서 그동안 언니한테 말하지 못했거든요.","JPN":"今まで照れくさくて、お姉ちゃんに言えなかったことがあります。ヘヘッ。","ENG":"I've been too shy to tell you something as well, you see.","TWN":"嘿嘿，我也因為害羞，一直有話也想對姐姐說。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};